/* BLAKE2b-256 in WebAssembly (Rust, wasm/blake2b/) — ~50x faster than pure-JS for the STARK prover's Merkle
 * hashing. Byte-identical to Python hashlib.blake2b(digest_size=32). Source lives in wasm/blake2b/src/lib.rs. */
const WASM_B64 = "";
let _hash = null;
function _decode(b64) {
  if (typeof atob !== "undefined") return Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));
  return Uint8Array.from(Buffer.from(b64, "base64"));
}
export async function initBlake2bWasm() {
  if (_hash) return _hash;
  const { instance } = await WebAssembly.instantiate(_decode(WASM_B64));
  const { memory, blake2b256 } = instance.exports;
  const IN = 64, OUT = 0;
  let mem = new Uint8Array(memory.buffer);
  _hash = (bytes) => {
    if (mem.buffer !== memory.buffer) mem = new Uint8Array(memory.buffer);
    mem.set(bytes, IN);
    blake2b256(IN, bytes.length, OUT);
    return mem.slice(OUT, OUT + 32);
  };
  return _hash;
}
